function safeText(value, fallback = '') {
  const text = String(value ?? '').trim();
  return text || fallback;
}

function extractSpreadsheetId(value) {
  const raw = safeText(value);
  if (!raw) return '';

  const match = raw.match(/\/spreadsheets\/d\/([a-zA-Z0-9-_]+)/);
  if (match && match[1]) return match[1];

  return raw;
}

const manifest = $('Extract Manifest JSON').first().json.manifest || {};
const sessionRow = $('Get Review Session').first().json.row || {};
const configMain = $('Config Main').first().json || {};

if (!manifest || typeof manifest !== 'object' || !Array.isArray(manifest.scenes)) {
  throw new Error('manifest is required before media generation');
}

const folderPath = safeText(sessionRow.folderPath);
if (!folderPath) {
  throw new Error('session folderPath is required before media generation');
}

const mediaSheetIdFromSession = extractSpreadsheetId(sessionRow.mediaSheetSpreadsheetUrl);
const mediaSheetIdFromConfig = extractSpreadsheetId(configMain.ttsSheetSpreadsheetId);
const ttsSheetSpreadsheetId = mediaSheetIdFromSession || mediaSheetIdFromConfig;
if (!ttsSheetSpreadsheetId) {
  throw new Error('mediaSheetId is required (sessionRow.mediaSheetSpreadsheetUrl or Config Main ttsSheetSpreadsheetId)');
}

const ttsFolderPath = folderPath.replace(/\/+$/g, '') + '/tts';

return {
  manifest,
  sessionRow,
  rootFolderId: safeText(configMain.ggDriveRootFolderId),
  ttsFolderPath,
  ttsVoiceId: safeText(configMain.ttsVoiceId, 'Ngoc'),
  ttsRequestTimeoutSec: Number(configMain.ttsRequestTimeoutSec || 600),
  ttsRetry: Number(configMain.ttsRetry || 2),
  ttsSheetSpreadsheetId,
  ttsSheetName: safeText(configMain.ttsSheetName, 'TTS'),
  mediaSheetSpreadsheetUrl: safeText(sessionRow.mediaSheetSpreadsheetUrl),
};

function safeText(value, fallback = '') {
  const text = String(value ?? '').trim();
  return text || fallback;
}

function asInt(value, fallback = 0) {
  const n = Number(value);
  return Number.isFinite(n) ? Math.floor(n) : fallback;
}

function pad3(value) {
  return String(value).padStart(3, '0');
}

const input = $json ?? {};
const manifest = input.manifest && typeof input.manifest === 'object' ? input.manifest : {};
const scenes = Array.isArray(manifest.scenes) ? [...manifest.scenes] : [];
scenes.sort((a, b) => asInt(a.order, 0) - asInt(b.order, 0));

const narrationItems = [];

for (const scene of scenes) {
  const sceneOrder = asInt(scene.order, narrationItems.length + 1);
  const sceneId = safeText(scene.scene_id, 'scene_' + pad3(sceneOrder));
  narrationItems.push({
    scene_id: sceneId,
    order: sceneOrder,
    scene_title: safeText(scene.scene_title),
    scene_role: safeText(scene.scene_role),
    narration_text: safeText(scene.narration_text),
    image_prompt_en: safeText(scene.image_prompt_en),
    highlight_quote_vi: safeText(scene.highlight_quote_vi),
    estimated_duration_sec: safeText(scene.estimated_duration_sec, 'cut'),
    total_chars: safeText(scene.total_chars, 'cut'),
    tts_file_name: 'scene_' + pad3(sceneOrder) + '.wav',
  });
}

return {
  ...input,
  narrationItems,
  narrationTotal: narrationItems.length,
};

function safeText(value, fallback = '') {
  const text = String(value ?? '').trim();
  return text || fallback;
}

const narrationItem = $('Loop Over Narration Items').item.json || {};
const ttsResult = $('Call TTS VieNeu').item.json || {};
const uploadResult = $json || {};

const ttsSuccess = safeText(ttsResult.status) === 'success';
const uploadSuccess = safeText(uploadResult.status) === 'success';
const ttsUrl = safeText(uploadResult.fileUrl);

let ttsStatus = 'failed';
let ttsErrorReason = '';

if (ttsSuccess && uploadSuccess && ttsUrl) {
  ttsStatus = 'success';
} else if (!ttsSuccess) {
  ttsErrorReason = safeText(ttsResult.errorReason, 'tts_failed');
} else {
  ttsErrorReason = safeText(uploadResult.errorMessage || uploadResult.error_reason || uploadResult.status, 'drive_upload_failed');
}

return {
  scene_id: safeText(narrationItem.scene_id),
  order: Number(narrationItem.order || 0),
  tts_url: ttsUrl,
  tts_status: ttsStatus,
  tts_error_reason: ttsErrorReason,
  tts_duration_sec: ttsResult.totalDurationSec
};

const rows = $input.all().map((item) => item.json || {});

const sorted = rows.sort((a, b) => {
  const orderDiff = Number(a.order || 0) - Number(b.order || 0);
  if (orderDiff !== 0) return orderDiff;
  return String(a.scene_id || '').localeCompare(String(b.scene_id || ''));
});

const ttsHeader = ['scene_id', 'tts_url', 'tts_duration_sec' ,'tts_status', 'tts_error_reason'];
const ttsDataRows = sorted.map((row) => [
  String(row.scene_id || ''),
  String(row.tts_url || ''),
  row.tts_duration_sec || 0,
  String(row.tts_status || ''),
  String(row.tts_error_reason || ''),
]);

const successCount = sorted.filter((row) => String(row.tts_status || '') === 'success').length;
const failedCount = sorted.length - successCount;

return [{
  json: {
    rows: [ttsHeader, ...ttsDataRows],
    ttsRowsTotal: sorted.length,
    ttsRowsSuccess: successCount,
    ttsRowsFailed: failedCount,
  },
}];

