function safeText(value, fallback = '') {
  const text = String(value ?? '').trim();
  return text || fallback;
}

const items = Array.isArray($json.items) ? $json.items : [];
const targetName = safeText($('Config Main').first().json.mediaSpreadsheetName);

const found = items.find((item) => {
  if (!item || typeof item !== 'object') return false;
  if (item.isFolder === true) return false;
  return safeText(item.name) === targetName;
});

function asInt(value, fallback = 0) {
  const n = Number(value);
  return Number.isFinite(n) ? Math.floor(n) : fallback;
}

const manifest = $('Prepare Manifest').first().json.manifest || {};
const mediaSpreadsheetName = safeText($('Config Main').first().json.mediaSpreadsheetName, 'Media');

const scenes = Array.isArray(manifest.scenes) ? [...manifest.scenes] : [];
scenes.sort((a, b) => asInt(a.order) - asInt(b.order));

const header = [
  'scene_id',
  'order',
  'scene_title',
  'scene_role',
  'narration_text',
  'image_prompt_en',
  'highlight_quote_vi',
  'estimated_duration_sec',
];

const dataRows = scenes.map((scene) => [
  safeText(scene.scene_id),
  asInt(scene.order, 0),
  safeText(scene.scene_title),
  safeText(scene.scene_role),
  safeText(scene.narration_text),
  safeText(scene.image_prompt_en),
  safeText(scene.highlight_quote_vi),
  asInt(scene.estimated_duration_sec, 0),
]);

const mediaSheetRows = [header, ...dataRows];

return {
  hasExistingMediaSheet: Boolean(found),
  existingMediaSheetUrl: safeText(found?.url),
  mediaSpreadsheetName: mediaSpreadsheetName,
  mediaSheetName: mediaSpreadsheetName,
  mediaSheetRows,
};
